python3 -c "
import json, glob, os
from pathlib import Path
WS = Path.home() / '.openclaw/workspace'
tickets = []
for f in glob.glob(str(WS / 'tickets/open/*.md')):
    try:
        content = open(f).read()
        company = ''
        for line in content.split('\n'):
            if 'company:' in line.lower(): company = line.split(':',1)[1].strip()
        if 'WorldDestinationClub' in company or 'wdc' in company.lower():
            tickets.append({'file': os.path.basename(f), 'path': f, 'content': content[:500]})
    except: pass
print(json.dumps({'count': len(tickets), 'tickets': tickets[:5]}))
"
